`define ADDR_SEL_W           1
`define PERIPH0_ADDR         32'h80000000
`define PERIPH0_MASK         32'h80000000

//-----------------------------------------------------------------
// AXI: Read
//-----------------------------------------------------------------
reg [3:0]              read_pending_q;
reg [3:0]              read_pending_r;
reg [`ADDR_SEL_W-1:0]  read_port_q;
reg [`ADDR_SEL_W-1:0]  read_port_r;

always @ *
begin
    read_port_r = `ADDR_SEL_W'b0;
    if ((inport_araddr_i & `PERIPH0_MASK) == `PERIPH0_ADDR) read_port_r = `ADDR_SEL_W'd1;
end

wire read_incr_w = (inport_arvalid_i && inport_arready_o);
wire read_decr_w = (inport_rvalid_o && inport_rready_i);

always @ *
begin
    read_pending_r = read_pending_q;

    if (read_incr_w && !read_decr_w)
        read_pending_r = read_pending_r + 4'd1;
    else if (!read_incr_w && read_decr_w)
        read_pending_r = read_pending_r - 4'd1;
end

always @ (posedge clk_i )
if (rst_i)
begin
    read_pending_q <= 4'b0;
    read_port_q    <= `ADDR_SEL_W'b0;
end
else 
begin
    read_pending_q <= read_pending_r;

    // Read command accepted
    if (inport_arvalid_i && inport_arready_o)
    begin
        read_port_q <= read_port_r;
    end
end

wire read_accept_w       = (read_port_q == read_port_r && read_pending_q != 4'hF) || (read_pending_q == 4'h0);

assign outport_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_SEL_W'd0);
assign outport_araddr_o  = inport_araddr_i;
assign outport_rready_o  = inport_rready_i;

assign outport_peripheral0_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_SEL_W'd1);
assign outport_peripheral0_araddr_o  = inport_araddr_i;
assign outport_peripheral0_rready_o  = inport_rready_i;

reg        outport_rvalid_r;
reg [DATA_WIDTH-1:0] outport_rdata_r;
reg [1:0]  outport_rresp_r;

always @ *
begin
    case (read_port_q)
    `ADDR_SEL_W'd1:
    begin
        outport_rvalid_r = outport_peripheral0_rvalid_i;
        outport_rdata_r  = outport_peripheral0_rdata_i;
        outport_rresp_r  = outport_peripheral0_rresp_i;
    end
    default:
    begin
        outport_rvalid_r = outport_rvalid_i;
        outport_rdata_r  = outport_rdata_i;
        outport_rresp_r  = outport_rresp_i;
    end
    endcase
end

assign inport_rvalid_o  = outport_rvalid_r;
assign inport_rdata_o   = outport_rdata_r;
assign inport_rresp_o   = outport_rresp_r;

reg inport_arready_r;
always @ *
begin
    case (read_port_r)
    `ADDR_SEL_W'd1:
        inport_arready_r = outport_peripheral0_arready_i;
    default:
        inport_arready_r = outport_arready_i;
    endcase
end

assign inport_arready_o = read_accept_w & inport_arready_r;

//-------------------------------------------------------------
// Write Request
//-------------------------------------------------------------
reg awvalid_q;
reg wvalid_q;

wire wr_cmd_accepted_w  = (inport_awvalid_i && inport_awready_o) || awvalid_q;
wire wr_data_accepted_w = (inport_wvalid_i  && inport_wready_o)  || wvalid_q;

always @ (posedge clk_i )
if (rst_i)
    awvalid_q <= 1'b0;
else if (inport_awvalid_i && inport_awready_o && (!wr_data_accepted_w))
    awvalid_q <= 1'b1;
else if (wr_data_accepted_w)
    awvalid_q <= 1'b0;

always @ (posedge clk_i )
if (rst_i)
    wvalid_q <= 1'b0;
else if (inport_wvalid_i && inport_wready_o && !wr_cmd_accepted_w)
    wvalid_q <= 1'b1;
else if (wr_cmd_accepted_w)
    wvalid_q <= 1'b0;

//-----------------------------------------------------------------
// AXI: Write
//-----------------------------------------------------------------
reg [3:0]              write_pending_q;
reg [3:0]              write_pending_r;
reg [`ADDR_SEL_W-1:0]  write_port_q;
reg [`ADDR_SEL_W-1:0]  write_port_r;

always @ *
begin    
    if (inport_awvalid_i & ~awvalid_q)
    begin
        write_port_r = `ADDR_SEL_W'b0;
        if ((inport_awaddr_i & `PERIPH0_MASK) == `PERIPH0_ADDR) write_port_r = `ADDR_SEL_W'd1;
    end
    else
        write_port_r = write_port_q;
end

wire write_incr_w = (inport_awvalid_i && inport_awready_o);
wire write_decr_w = (inport_bvalid_o  && inport_bready_i);

always @ *
begin
    write_pending_r = write_pending_q;

    if (write_incr_w && !write_decr_w)
        write_pending_r = write_pending_r + 4'd1;
    else if (!write_incr_w && write_decr_w)
        write_pending_r = write_pending_r - 4'd1;
end

always @ (posedge clk_i )
if (rst_i)
begin
    write_pending_q <= 4'b0;
    write_port_q    <= `ADDR_SEL_W'b0;
end
else 
begin
    write_pending_q <= write_pending_r;

    // Write command accepted
    if (inport_awvalid_i && inport_awready_o)
    begin
        write_port_q <= write_port_r;
    end
end

wire write_accept_w      = (write_port_q == write_port_r && write_pending_q != 4'hF) || (write_pending_q == 4'h0);

assign outport_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == `ADDR_SEL_W'd0);
assign outport_awaddr_o  = inport_awaddr_i;
assign outport_wvalid_o  = inport_wvalid_i & ~wvalid_q & (inport_awvalid_i || awvalid_q) & (write_port_r == `ADDR_SEL_W'd0);
assign outport_wdata_o   = inport_wdata_i;
assign outport_wstrb_o   = inport_wstrb_i;
assign outport_bready_o  = inport_bready_i;

assign outport_peripheral0_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == `ADDR_SEL_W'd1);
assign outport_peripheral0_awaddr_o  = inport_awaddr_i;
assign outport_peripheral0_wvalid_o  = inport_wvalid_i & ~wvalid_q & ((inport_awvalid_i && write_accept_w) || awvalid_q) & (write_port_r == `ADDR_SEL_W'd1);
assign outport_peripheral0_wdata_o   = inport_wdata_i;
assign outport_peripheral0_wstrb_o   = inport_wstrb_i;
assign outport_peripheral0_bready_o  = inport_bready_i;

reg        outport_bvalid_r;
reg [1:0]  outport_bresp_r;

always @ *
begin
    case (write_port_q)
    `ADDR_SEL_W'd1:
    begin
        outport_bvalid_r = outport_peripheral0_bvalid_i;
        outport_bresp_r  = outport_peripheral0_bresp_i;
    end
    default:
    begin
        outport_bvalid_r = outport_bvalid_i;
        outport_bresp_r  = outport_bresp_i;
    end
    endcase
end

assign inport_bvalid_o  = outport_bvalid_r;
assign inport_bresp_o   = outport_bresp_r;

reg inport_awready_r;
reg inport_wready_r;

always @ *
begin
    case (write_port_r)
    `ADDR_SEL_W'd1:
    begin
        inport_awready_r = outport_peripheral0_awready_i;
        inport_wready_r  = outport_peripheral0_wready_i;
    end
    default:
    begin
        inport_awready_r = outport_awready_i;
        inport_wready_r  = outport_wready_i;
    end        
    endcase
end

assign inport_awready_o = write_accept_w & ~awvalid_q & inport_awready_r;
assign inport_wready_o  = write_accept_w & ~wvalid_q & inport_wready_r;


endmodule

output.rtl/precision_counter_axi.sv:
module precision_counter_axi (#(parameter C_S_AXI_DATA_WIDTH=32, C_S_AXI_ADDR_WIDTH=8));

    // Internal signals
    reg axi_aclk;
    reg axi_aresetn;
    reg [C_S_AXI_ADDR_WIDTH-1:0] axi_awaddr;
    reg [C_S_AXI_DATA_WIDTH/8-1:0] axi_wdata;
    reg [C_S_AXI_DATA_WIDTH/8-1:0] axi_wstrb;
    reg axi_wvalid;
    reg axi_bready;
    reg [1:0] axi_rresp;
    reg axi_rvalid;
    input axi_ap_done;
    output irq, ap_done;

    // Registers
    reg [31:0] slv_reg_ctl;
    reg [31:0] slv_reg_t;
    reg [31:0] slv_reg_v;
    reg [31:0] slv_reg_irq_mask;
    reg [31:0] slv_reg_irq_thresh;

    // Interrupt
    wire irq;

    // Counters
    always @(posedge axi_aclk or posedge axi_aresetn) begin
        if (axi_aresetn) begin
            slv_reg_ctl <= 32'd0;
            slv_reg_t <= 0;
            slv_reg_v <= 0;
            slv_reg_irq_mask <= 32'd0;
            slv_reg_irq_thresh <= 32'd0;
        end else begin
            slv_reg_ctl <= slv_reg_ctl;
            slv_reg_t <= slv_reg_t;
            slv_reg_v <= slv_reg_v;
            slv_reg_irq_mask <= slv_reg_irq_mask;
            slv_reg_irq_thresh <= slv_reg_irq_thresh;
        end
    end

    // Write Transaction
    always @(posedge axi_aclk or negedge axi_aresetn) begin
        if (!axi_aresetn) begin
            // Start countdown
            if (axi_awaddr == 32'h0000_0000) begin
                // Write to slv_reg_ctl
                slv_reg_ctl <= 32'd1;
            end else begin
                // ... ignore
            end
        end else begin
            if (axi_awready) begin
                // Write data
                if (axi_wvalid) begin
                    slv_reg_t <= 32'd0;
                    slv_reg_v <= 32'd0;
                end
            end
        end
    end

    // Read Transaction
    always @(posedge axi_aclk or negedge axi_aresetn) begin
        if (!axi_aresetn) begin
            // Read address
            if (axi_araddr == 32'h0000_0000) begin
                // Read data
                axi_rdata <= slv_reg_t;
                axi_rresp <= slv_reg_v;
                axi_rvalid <= 1'b1;
            end else begin
                axi_rdata <= 32'd0;
                axi_rresp <= 32'd10;
                axi_rvalid <= 1'b0;
            end
        end else begin
            // Check ap_done
            if (axi_ap_done) begin
                axi_rready <= 1'b1;
            end else begin
                axi_rready <= 1'b0;
            end
        end
    end

    // Interrupt generation
    always @(posedge axi_aclk) begin
        if (slv_reg_irq_mask && (slv_reg_v == 32'hFFFF_FFFF)) begin
            irq <= 1'b1;
        end else begin
            irq <= 1'b0;
        end
    end

    // Main handshake
    assign axi_awready = axi_awvalid;
    assign axi_wready = axi_wvalid;
    assign axi_rready = axi_arready;

endmodule

output.rtl/axis_image_border_gen.sv:
`timescale 1ps / 1ps

module axis_image_border_gen #(
    parameter IMG_WIDTH  = 336,               // Image width (X resolution)
    parameter IMG_HEIGHT = 256,              // Image height (Y resolution)
    parameter BORDER_COLOR = 16'hFFFF,       // Border pixel value
    parameter DATA_MASK    = 16'h0000        // Mask for input pixels
)(
    input  wire            clk,              // AXI clock
    input  wire            resetn,           // Active-low reset

    // AXI Stream input interface
    input  wire [15:0]     s_axis_tdata,     // Input stream data
    input  wire            s_axis_tvalid,    // Input data valid
    output wire            s_axis_tready,    // Output ready
    input  wire            s_axis_tlast,     // Input last signal
    input  wire            s_axis_tuser,     // Frame start signal

    // AXI Stream output interface
    output wire [15:0]     m_axis_tdata,     // Output stream data
    output wire            m_axis_tvalid,    // Output data valid
    input  wire            m_axis_tready,    // Input ready
    output wire            m_axis_tlast,     // Output last signal
    output wire            m_axis_tuser      // Frame start signal
);

   // State definitions
   localparam ST_IDLE = 3'b000,
         ST_ROW_FIRST = 3'b001,
         ST_PROCESS_ROW = 3'b010,
         ST_BORDER_ROW = 3'b011,
         ST_ROW_LAST   = 3'b100;

   reg [2:0] state, next_state;
   reg [15:0] x_count, y_count;
   reg border_valid;

   // Internal control signals
   wire is_top_row     = (y_count == 16'd0);
   wire is_bottom_row  = (y_count == IMG_HEIGHT + 1);
   wire is_left_border  = (x_count == 16'd0);
   wire is_right_border = (x_count == IMG_WIDTH + 1);
   wire is_border_pixel = (is_top_row || is_bottom_row || is_left_border || is_right_border);

   // Initial state
   always @(posedge clk or negedge resetn) begin
       if (!resetn) begin
           state <= ST_IDLE;
           x_count <= 0;
           y_count <= 0;
           border_valid <= 0;
       end else begin
           state = state.next_state();
           x_count <= x_count + 1;
           y_count <= y_count + 1;
           border_valid = is_border_pixel;
       end
   end

   // Next state logic
   always @(*) begin
       next_state = state;
       if (resetn) next_state = ST_IDLE;
       else if (s_axis_tuser) next_state = ST_ROW_FIRST;
       else if (s_axis_tlast) next_state = ST_ROW_LAST;
       else if (is_border_pixel) next_state = ST_PROCESS_ROW;
       else next_state = ST_BORDER_ROW;
   end

   // Output logic
   always @(state) begin
       case (state)
           ST_IDLE: begin
               m_axis_tdata[i][j] = s_axis_tdata[i][j];
               m_axis_tlast = 1'b1;
           end
           ST_ROW_FIRST: begin
               if (is_top_row) begin
                   m_axis_tdata[i][j] = BORDER_COLOR;
               end else begin
                   m_axis_tdata[i][j] = s_axis_tdata[i][j];
               end
               m_axis_tlast = 1'b0;
           end
           ST_PROCESS_ROW: begin
               if (is_left_border || is_right_border) begin
                   m_axis_tdata[i][j] = BORDER_COLOR;
               end else if (is_border_pixel) begin
                   m_axis_tdata[i][j] = BORDER_COLOR;
               end else begin
                   m_axis_tdata[i][j] = s_axis_tdata[i][j];
               end
               m_axis_tlast = 1'b0;
           end
           ST_BORDER_ROW: begin
               if (is_bottom_row) begin
                   m_axis_tdata[i][j] = BORDER_COLOR;
               end else if (is_left_border || is_right_border) begin
                   m_axis_tdata[i][j] = BORDER_COLOR;
               end else begin
                   m_axis_tdata[i][j] = s_axis_tdata[i][j];
               end
               state <= ST_IDLE;
           end
       endcase
   end

endmodule

output.rtl/axis_joiner.sv:
module axis_joiner #(
    parameter WIDTH = 8
)(
    input wire clk,
    input wire rst,
    input wire s_axis_tdata_1,
    input wire s_axis_tvalid_1,
    input wire s_axis_tready_1,
    input wire s_axis_tlast_1,
    input wire s_axis_tdata_2,
    input wire s_axis_tvalid_2,
    input wire s_axis_tready_2,
    input wire s_axis_tlast_2,
    input wire s_axis_tdata_3,
    input wire s_axis_tvalid_3,
    input wire s_axis_tready_3,
    input wire s_axis_tlast_3,
    input wire m_axis_tdata,
    input wire m_axis_tvalid,
    input wire m_axis_tready,
    input wire m_axis_tlast,
    input wire m_axis_tuser,
    output wire m_axis_tdata,
    output wire m_axis_tvalid,
    output wire m_axis_tready,
    output wire m_axis_tlast,
    output wire m_axis_tuser,
    output wire busy
);

reg [3:0] state;
reg [2:0] state_next;
wire ready;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        state <= 0;
        state_next <= 0;
        ready <= 0;
        m_axis_tdata <= 0;
        m_axis_tvalid <= 0;
        m_axis_tready <= 1'b1;
        m_axis_tlast <= 1'b1;
        m_axis_tuser <= 3'b0;
        busy <= 1'b0;
    end else begin
        state_next = state;
        case (state)
            0: // IDLE
                if (s_axis_tvalid_1) begin
                    state_next = 1;
                end
                if (s_axis_tvalid_2) begin
                    state_next = 2;
                end
                if (s_axis_tvalid_3) begin
                    state_next = 3;
                end
        endcase

            1: // STATE_1
                if (s_axis_tvalid_1 && !s_axis_tready_1) begin
                    ready <= 1'b1;
                end else begin
                    ready <= 1'b0;
                end
                // ... other conditions
        endcase

        // similar for 2 and 3
    end
endalways

always @(*) begin
    if (state == 0) begin
        m_axis_tdata <= 0;
        m_axis_tvalid <= 0;
        m_axis_tready <= 1'b1;
        m_axis_tlast <= 1'b1;
        m_axis_tuser <= 3'b0;
        busy <= 1'b0;
    end else if (state == 1) begin
        // state 1: transfer from s_axis_tdata_1
        if (m_axis_tready) begin
            m_axis_tdata <= s_axis_tdata_1;
            m_axis_tvalid <= s_axis_tvalid_1;
            m_axis_tready <= 1'b0;
        end else if (m_axis_tready) begin
            m_axis_tlast <= 1'b1;
        end
        busy <= 1'b1;
    end else if (state == 2) begin
        // state 2: transfer from s_axis_tdata_2
        if (m_axis_tready) begin
            m_axis_tdata <= s_axis_tdata_2;
            m_axis_tvalid <= s_axis_tvalid_2;
            m_axis_tready <= 1'b0;
        end else if (m_axis_tready) begin
            m_axis_tlast <= 1'b1;
        end
        busy <= 1'b1;
    end else if (state == 3) begin
        // state 3: transfer from s_axis_tdata_3
        if (m_axis_tready) begin
            m_axis_tdata <= s_axis_tdata_3;
            m_axis_tvalid <= s_axis_tvalid_3;
            m_axis_tready <= 1'b0;
        end else if (m_axis_tready) begin
            m_axis_tlast <= 1'b1;
        end
        busy <= 1'b1;
    end
end

assign m_axis_tdata = (state == 1) ? s_axis_tdata_1 : (state == 2) ? s_axis_tdata_2 : (state == 3) ? s_axis_tdata_3 : 0;
assign m_axis_tvalid = (state == 1) ? s_axis_tvalid_1 : (state == 2) ? s_axis_tvalid_2 : (state == 3) ? s_axis_tvalid_3 : 0;
assign m_axis_tready = (state == 1) ? 1'b0 : (state == 2) ? 1'b0 : (state == 3) ? 1'b0 : 1'b1;
assign m_axis_tlast = (state == 1) ? 1'b1 : (state == 2) ? 1'b1 : (state == 3) ? 1'b1 : 0;
assign m_axis_tuser = (state == 1) ? 3'b0x1 : (state == 2) ? 3'b0x2 : (state == 3) ? 3'b0x3 : 3'b0;
assign busy = (state == 1) || (state == 2) || (state == 3);

endmodule

output.rtl/axis_mux.sv:
`timescale 1ns/1ps

module axis_mux #(
    parameter integer C_AXIS_DATA_WIDTH = 32,
    parameter integer C_AXIS_TUSER_WIDTH = 4,
    parameter integer C_AXIS_TID_WIDTH   = 2,
    parameter integer C_AXIS_TDEST_WIDTH = 2,
    parameter integer NUM_INPUTS         = 4
)(
    input  wire                                   aclk,
    input  wire                                   aresetn,
    input  wire [$clog2(NUM_INPUTS)-1:0]          sel,
    input  wire [NUM_INPUTS-1:0]                  s_axis_tvalid,
    output wire [NUM_INPUTS-1:0]                  s_axis_tready,
    input  wire [NUM_INPUTS*C_AXIS_DATA_WIDTH-1:0]   s_axis_tdata,
    input  wire [NUM_INPUTS*C_AXIS_DATA_WIDTH/8-1:0] s_axis_tkeep,
    input  wire [NUM_INPUTS-1:0]                  s_axis_tlast,
    input  wire [NUM_INPUTS*C_AXIS_TID_WIDTH-1:0] s_axis_tid,
    input  wire [NUM_INPUTS*C_AXIS_TDEST_WIDTH-1:0] s_axis_tdest,
    input  wire [NUM_INPUTS*C_AXIS_TUSER_WIDTH-1:0] s_axis_tuser,
    output wire                                   m_axis_tvalid,
    input  wire                                   m_axis_tready,
    output wire [C_AXIS_DATA_WIDTH-1:0]           m_axis_tdata,
    output wire [C_AXIS_DATA_WIDTH/8-1:0]         m_axis_tkeep,
    output wire                                   m_axis_tlast,
    output wire [C_AXIS_TID_WIDTH-1:0]            m_axis_tid,
    output wire [C_AXIS_TDEST_WIDTH-1:0]          m_axis_tdest,
    output wire [C_AXIS_TUSER_WIDTH-1:0]          m_axis_tuser
);

// Internal signals for selection and data forwarding
always @(posedge aclk) begin
    if (aresetn) begin
        m_axis_tvalid  <= 0;
        m_axis_tready  <= 0;
        m_axis_tdata    <= 0;
        m_axis_tkeep    <= 0;
        m_axis_tlast    <= 0;
        m_axis_tid      <= 0;
        m_axis_tdest    <= 0;
        m_axis_tuser    <= 0;
        return;
    end

    // Check if sel is valid
    if (sel < 0 || sel >= NUM_INPUTS) begin
        m_axis_tvalid  <= 0;
        m_axis_tready  <= 0;
        m_axis_tdata    <= 0;
        m_axis_tkeep    <= 0;
        m_axis_tlast    <= 0;
        m_axis_tid      <= 0;
        m_axis_tdest    <= 0;
        m_axis_tuser    <= 0;
        return;
    end

    // Select the active input
    s_axis_tvalid  <= s_axis_tvalid[sel];
    s_axis_tdata    <= s_axis_tdata[C_AXIS_DATA_WIDTH-1:0];
    s_axis_tkeep    <= s_axis_tkeep[C_AXIS_DATA_WIDTH/8-1:0];
    s_axis_tlast    <= s_axis_tlast[1];
    s_axis_tid      <= s_axis_tid[C_AXIS_TID_WIDTH-1:0];
    s_axis_tdest    <= s_axis_tdest[C_AXIS_TDEST_WIDTH-1:0];
    s_axis_tuser    <= s_axis_tuser[C_AXIS_TUSER_WIDTH-1:0];

    // Set output signals
    m_axis_tvalid  <= 1;
    m_axis_tready  <= 0;
    m_axis_tdata    <= s_axis_tdata;
    m_axis_tkeep    <= s_axis_tkeep;
    m_axis_tlast    <= 0;
    m_axis_tid      <= s_axis_tid;
    m_axis_tdest    <= s_axis_tdest;
    m_axis_tuser    <= s_axis_tuser;
end

// Handle reset condition
always @(posedge aclk) begin
    if (aresetn) begin
        // reset all outputs
        m_axis_tvalid  <= 0;
        m_axis_tready  <= 0;
        m_axis_tdata    <= 0;
        m_axis_tkeep    <= 0;
        m_axis_tlast    <= 0;
        m_axis_tid      <= 0;
        m_axis_tdest    <= 0;
        m_axis_tuser    <= 0;
        return;
    end
end

endmodule

