module barrel_shifter #(
    parameter data_width = 16,     
    parameter shift_bits_width = 4  
)(
    input [data_width-1:0] data_in,
    input [shift_bits_width-1:0] shift_bits,
    input [2:0] mode,             
    input left_right,              
    input [data_width-1:0] mask,   
    input enable,                  
    input enable_parity,           
    output reg [data_width-1:0] data_out,
    output reg parity_out,        
    output reg error_signaling,     // 2-bit for error type
    output reg error_code,          // 2'bXXX, but we can just use error_signaling for output
    output reg parity_out,        
    output reg error                -- we can keep the same name? Actually, the original had error. But the requirement says 2-bit. So we can change to 2-bit. But the user might expect the same name. Let's keep 'error' as 2'b? Actually, we can rename to error_signaling and have two bits.
    output reg [data_width-1:0] data_out,
    output reg parity_out,        
    output reg error_signaling        -- new 2-bit signal
);

// error_signaling: high bit indicates error, low bit indicates no error.
assign error_signaling = 1'b0;

always @(*) begin
    if (!enable) begin
        data_out <= data_in;
        error_signaling <= 2'b00;
        parity_out <= 0;
    end else begin
        error_signaling <= 2'b00;
        case (mode)
            3'b000: begin
                if (shift_bits >= data_width) begin
                    error_signaling <= 2'b10;
                    data_out <= {data_width{1'b0}};
                end else if (left_right) begin
                    data_out <= data_in << shift_bits;
                end else begin
                    data_out <= data_in >> shift_bits;
                end
            end
            3'b001: begin
                if (shift_bits >= data_width) begin
                    error_signaling <= 2'b10;
                    data_out <= {data_width{1'b0}};
                end else if (left_right) begin
                    data_out <= data_in << shift_bits;
                end else begin
                    data_out <= data_in >> shift_bits;
                end
            end
            3'b010: begin
                if (shift_bits >= data_width) begin
                    error_signaling <= 2'b10;
                    data_out <= {data_width{1'b0}};
                end else if (left_right) begin
                    data_out <= (data_in << shift_bits) | (data_in >> (data_width - shift_bits));
                end else begin
                    data_out <= (data_in >> shift_bits) | (data_in << (data_width - shift_bits));
                end
            end
            3'b011: begin
                if (shift_bits >= data_width) begin
                    error_signaling <= 2'b10;
                    data_out <= {data_width{1'b0}};
                end else if (left_right) begin
                    data_out <= (data_in << shift_bits) & mask;
                end else begin
                    data_out <= (data_in >> shift_bits) & mask;
                end
            end
            3'b100: begin
                if (left_right) begin
                    data_out <= data_in + shift_bits;
                end else begin
                    data_out <= data_in - shift_bits;
                end
            end
            3'b101: begin
                data_out <= 0;
                for (int i = data_width-1; i >= 0; i = i - 1) begin
                    if (data_in[i] == 1 && data_out == 0) begin
                        data_out <= i;
                    end
                end
            end
            3'b110: begin
                if (left_right) begin
                    data_out <= (data_in + shift_bits) % data_width;
                end else begin
                    data_out <= (data_in - shift_bits) % data_width;
                end
            end
            default: begin
                data_out <= {data_width{1'b0}};
                error_signaling <= 2'b01;
            end
        endcase
    end

    if (enable_parity) begin
        parity_out <= ^data_out;
    end else begin
        parity_out <= 0;
    end
end

endmodule

