            shift_reg = binary_in;
        end
        else begin
            shift_reg = {BCD_DIGITS*4{1'b0}};
        end

        // Directional processing
        always_comb begin
            if (switch == 1) begin
                // Binary → BCD
                for (int i = 0; i < BCD_DIGITS; i++) begin
                    temp = shift_reg << 1;
                    if (temp[11:8] >= 5) temp[11:8] = temp[11:8] + 3;
                    if (temp[15:12] >= 5) temp[15:12] = temp[15:12] + 3;
