module cdc_pulse_synchronizer (
    input  logic src_clock,   // Source Clock Domain
    input  logic des_clock,   // Destination Clock Domain
    input  logic rst_in,      // Reset
    input  logic src_pulse,   // Source Pulse
    output logic des_pulse    // Destination Pulse
);

    logic pls_toggle;      
    logic pls_toggle_synca;
    logic pls_toggle_syncc;

    //--------------------------------------------------
    //   Toggle Flop Circuit
    //---------------------------------------------------

    always_ff @(posedge src_clock or posedge rst_in) begin
        if (rst_in) begin
            pls_toggle <= 1'b0;
        end else if (src_pulse) begin
            pls_toggle <= ~pls_toggle;
        end else begin
            pls_toggle <= 1'b0;
        end
    end

    //--------------------------------------------------
    //   Double Flop Bit Synchronizer
    //---------------------------------------------------

    always_ff @(posedge des_clock or posedge rst_in) begin
        if (rst_in) begin
            pls_toggle_synca <= 1'b0;
        end else begin
            pls_toggle_synca <= pls_toggle;
        end
    end

    //--------------------------------------------------
    //   Delay Logic of Output signal
    //---------------------------------------------------

    always_ff @(posedge des_clock or posedge rst_in) begin
        if (rst_in) begin
            pls_toggle_syncc <= 1'b0;
        end else begin
            pls_toggle_syncc <= pls_toggle_synca;
        end
    end

    //--------------------------------------------------
    //   Assign Statement for posedge and negedge detection
    //---------------------------------------------------

    assign des_pulse = pls_toggle_syncc ^ pls_toggle_synca; 
endmodule

input.rtl/cdc_pulse_synchronizer.sv:
module cdc_pulse_synchronizer (
    input  logic src_clock,       // Source Clock Domain
    input  logic des_clock,       // Destination Clock Domain
    input  logic rst_in,          // Asynchronous Active-High Reset
    input  logic src_pulse,       // Source Pulse
    output logic des_pulse        // Destination Pulse
);

    logic pls_toggle;      
    logic pls_toggle_synca, pls_toggle_syncb, pls_toggle_syncc;
    logic rst_src_sync;
    logic rst_des_sync;
    logic rst_src_synca, rst_src_syncb;
    logic rst_des_synca, rst_des_syncb;

    always_ff @(posedge src_clock or posedge rst_in) begin
        if (rst_in) begin
            rst_src_synca <= 1'b1;
            rst_src_syncb <= 1'b1;
        end else begin
            rst_src_synca <= 1'b0;
            rst_src_syncb <= rst_src_synca;
        end
    end

    assign rst_src_sync = rst_src_syncb;

    always_ff @(posedge des_clock or posedge rst_in) begin
        if (rst_in) begin
            rst_des_synca <= 1'b1;
            rst_des_syncb <= 1'b1;
        end else begin
            rst_des_synca <= 1'b0;
            rst_des_syncb <= rst_des_synca;
        end
    end

    assign rst_des_sync = rst_des_syncb;

    always_ff @(posedge src_clock or posedge rst_src_sync) begin
        if (rst_src_sync) begin
            pls_toggle <= 1'b0;
        end else if (src_pulse) begin
            pls_toggle <= ~pls_toggle;
        end
    end

    always_ff @(posedge des_clock or posedge rst_des_sync) begin
        if (rst_des_sync) begin
            pls_toggle_synca <= 1'b0;
            pls_toggle_syncb <= 1'b0;
        end else begin
            pls_toggle_synca <= pls_toggle;
            pls_toggle_syncb <= pls_toggle_synca;
        end
    end

    always_ff @(posedge des_clock or posedge rst_des_sync) begin
        if (rst_des_sync) begin
            pls_toggle_syncc <= 1'b0;
        end else begin
            pls_toggle_syncc <= pls_toggle_syncb;
        end
    end

    assign des_pulse = pls_toggle_syncc ^ pls_toggle_syncb;

endmodule

output.rtl/cdc_pulse_synchronizer.sv:
module cdc_pulse_synchronizer (
    input  logic src_clock,       // Source Clock Domain
    input  logic des_clock,       // Destination Clock Domain
    input  logic rst_in,          // Asynchronous Active-High Reset
    input  logic src_pulse,       // Source Pulse
    output logic [NUM_CHANNELS-1:0] des_pulse        // Destination Pulse
);

    logic pls_toggle_i, pls_toggle_synca_i, pls_toggle_syncb_i;
    logic rst_src_sync_i;

    always_ff @(posedge src_clock or posedge rst_in) begin
        if (rst_in) begin
            rst_src_sync_i <= 1'b1;
            pls_toggle_i <= 1'b0;
        end else begin
            rst_src_sync_i <= 1'b0;
            pls_toggle_i <= 1'b0;
        end
    end

    always_ff @(posedge des_clock or posedge rst_in) begin
        if (rst_in) begin
            rst_des_sync_i <= 1'b1;
            pls_toggle_synca_i <= 1'b0;
            pls_toggle_syncb_i <= 1'b0;
        end else begin
            rst_des_sync_i <= 1'b0;
            pls_toggle_synca_i <= pls_toggle_i;
            pls_toggle_syncb_i <= pls_toggle_synca_i;
        end
    end

    always_ff @(posedge src_clock or posedge rst_src_sync_i) begin
        if (rst_src_sync_i) begin
            pls_toggle_i <= 1'b0;
        end else if (src_pulse) begin
            pls_toggle_i <= ~pls_toggle_i;
        end
    end

    always_ff @(posedge des_clock or posedge rst_des_sync_i) begin
        if (rst_des_sync_i) begin
            pls_toggle_synca_i <= 1'b0;
            pls_toggle_syncb_i <= 1'b0;
        end else begin
            pls_toggle_synca_i <= pls_toggle_i;
            pls_toggle_syncb_i <= pls_toggle_synca_i;
        end
    end

    always_ff @(posedge des_clock or posedge rst_des_sync_i) begin
        if (rst_des_sync_i) begin
            pls_toggle_syncc_i <= 1'b0;
        end else begin
            pls_toggle_syncc_i <= pls_toggle_synca_i;
        end
    end

    always_ff @(posedge des_clock or posedge rst_des_sync_i) begin
        if (rst_des_sync_i) begin
            pls_toggle_syndd_i <= 1'b0;
        end else begin
            pls_toggle_syndd_i <= pls_toggle_syncc_i;
        end
    end

    genvar i;
    generate
        for (gvar j = 0; j < NUM_CHANNELS; j = j + 1) begin
            assign des_pulse[j] = pls_toggle_syncc_j ^ pls_toggle_syncb_j;
        end
    endgenerate

endmodule

