module crossbar_switch #(
    parameter DATA_WIDTH = 8,
    localparam NUM_PORTS = 4,
    localparam DATA_WIDTH_IN = (DATA_WIDTH + $clog2(NUM_PORTS))
)(
    input  logic                        clk,
    input  logic                        reset,
    // Input data and destination IDs
    input  logic [DATA_WIDTH_IN-1 :0]  in0, in1, in2, in3,
    input  logic                       valid_in0, valid_in1, valid_in2, valid_in3,
    // Output data
    output logic  [DATA_WIDTH-1:0]      out0, out1, out2, out3,
    output logic                        valid_out0, valid_out1, valid_out2, valid_out3
);

// Internal Signals
logic [$clog2(NUM_PORTS)-1 : 0] dest0, dest1, dest2, dest3;

// ----------------------------------------
// - Procedural blocks
// ----------------------------------------
always @(posedge clk or negedge reset) begin
    if (!reset) begin
        out0 <= 0; out1 <= 0; out2 <= 0; out3 <= 0;
        valid_out0 <= valid_out1 <= valid_out2 <= valid_out3 <= 1'b0;
    end else begin
        out0 <= 0; out1 <= 0; out2 <= 0; out3 <= 0;
        valid_out0 <= 1'b0; valid_out1 <= 1'b0; valid_out2 <= 1'b0; valid_out3 <= 1'b0;

        if (valid_in0 == 1) begin
            out0 <= in0;
            valid_out0 <= 1;
            out1 <= 0;
            out2 <= 0;
            out3 <= 0;
            valid_out0 <= 1;
            valid_out1 <= 0;
            valid_out2 <= 0;
            valid_out3 <= 0;
        end else if (valid_in1 == 1) begin
            out0 <= 0;
            out1 <= in1;
            out2 <= 0;
            out3 <= 0;
            valid_out0 <= 0;
            valid_out1 <= 1;
            valid_out2 <= 0;
            valid_out3 <= 0;
        end else if (valid_in2 == 1) begin
            out0 <= 0;
            out1 <= 0;
            out2 <= in2;
            out3 <= 0;
            valid_out0 <= 0;
            valid_out1 <= 0;
            valid_out2 <= 1;
            valid_out3 <= 0;
        end else if (valid_in3 == 1) begin
            out0 <= 0;
            out1 <= 0;
            out2 <= 0;
            out3 <= in3;
            valid_out0 <= 0;
            valid_out1 <= 0;
            valid_out2 <= 0;
            valid_out3 <= 1;
        end else begin
            out0 <= 0; out1 <= 0; out2 <= 0; out3 <= 0;
            valid_out0 <= 0; valid_out1 <= 0; valid_out2 <= 0; valid_out3 <= 0;
        end
    end
end

// ----------------------------------------
// - Combinational Assignments
// ----------------------------------------
assign dest0 = in0[DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2];
assign dest1 = in1[DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2];
assign dest2 = in2[DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2];
assign dest3 = in3[DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2];

endmodule

output.rtl/data_bus_controller.sv:
module data_bus_controller #(
  parameter AFINITY = 0
) (
  input         clk,
  input         rst_n,

  output        m0_read,
  input         m0_valid,
  input [31:0]  m0_data,

  output        m1_read,
  input         m1_valid,
  input [31:0]  m1_data,

  output        s_read,
  output        s_valid,
  output [31:0] s_data
);

  reg [31:0] slave_data;
  reg m0_ready, m1_ready;
  reg m0_valid, m1_valid;
  reg s_ready;

  always_comb begin
    // First‑come, first‑served decision based on AFINITY
    if (~m0_ready && ~m1_ready) begin
      // No masters ready – nothing happens
    end else if (m0_ready && m1_ready) begin
      if (AFINITY == 0) begin
        slave_data <= m0_data;
        m0_read = 1;
        m0_valid = 0;
        m1_ready = 1;
        m1_valid = 0;
      end else begin
        slave_data <= m1_data;
        m1_read = 1;
        m1_valid = 0;
        m0_ready = 1;
        m0_valid = 0;
      end
    end else if (m0_ready && !m1_ready) begin
      slave_data <= m0_data;
      m0_read = 1;
      m0_valid = 0;
      m1_ready = 1;
      m1_valid = 0;
    end else if (!m0_ready && m1_ready) begin
      slave_data <= m1_data;
      m1_read = 1;
      m1_valid = 0;
      m0_ready = 1;
      m0_valid = 0;
    end else
      // Both masters ready – use AFINITY to choose
      slave_data <= {m0_data, m1_data};
      m0_read = 0;
      m1_read = 0;
  end

  always_ff @(posedge clk) begin
    // Update read outputs
    m0_read = m0_valid;
    m0_valid = 0;
    m1_read = m1_valid;
    m1_valid = 0;
    s_valid = s_ready;
    s_ready = ~s_valid;
  end

  // Output the data from the masters
  assign m0_ready   = AFINITY == 0 ? 1 : 0;
  assign m1_ready   = AFINITY == 1 ? 1 : 0;
  assign s_read     = true;
  assign s_valid    = false;
  assign s_data     = {};

endmodule

input.rtl/data_serializer.sv:
module data_serializer #(
  parameter DATA_W   = 8,
  parameter BIT_ORDER= 0,
  parameter PARITY   = 0
)(
  input                  clk,
  input                  reset,
  // Parallel data interface
  input                  p_valid_i,
  input  [DATA_W-1:0]    p_data_i,
  output                 p_ready_o,
  // Serial data interface
  output                 s_valid_o,
  output                 s_data_o,
  input                  s_ready_i,
  // Transmission enable
  input                  tx_en_i
);

  // Local constants
  localparam ST_RX = 1'b0;
  localparam ST_TX = 1'b1;

  // If PARITY != 0 => We use 1 extra bit for parity
  localparam EXTRA_BIT = (PARITY == 0) ? 0 : 1;
  localparam SHIFT_W   = DATA_W + EXTRA_BIT;

  // Internal regs
  reg                    state_q, state_d;
  reg  [SHIFT_W-1:0]     shift_reg_q, shift_reg_d;
  reg  [$clog2(SHIFT_W)-1:0] count_q, count_d;

  // Parity calculation
  wire parity_bit_even = ^p_data_i;   // XOR => "even"
  wire parity_bit_odd  = ~^p_data_i;  // invert XOR => "odd"

  wire parity_bit = (PARITY == 1) ? parity_bit_even :
                    (PARITY == 2) ? parity_bit_odd  :
                                    1'b0; // NONE

  // Sequential state & register updates
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      state_q     <= ST_RX;
      shift_reg_q <= {SHIFT_W{1'b0}};
      count_q     <= 0;
    end else begin
      state_q     <= state_d;
      shift_reg_q <= shift_reg_d;
      count_q     <= count_d;
    end
  end

  // Next-state logic
  always @* begin
    // Default assignments
    state_d     = state_q;
    shift_reg_d = shift_reg_q;
    count_d     = count_q;

    case (state_q)

      // ST_RX: Load parallel data + parity
      ST_RX: begin
        if (p_valid_i) begin
          if (BIT_ORDER == 0) begin
            // LSB-first => store LSB in shift_reg_d[0]
            if (EXTRA_BIT == 1)
              shift_reg_d = {parity_bit, p_data_i};  // 9 bits if PARITY!=0
            else
              shift_reg_d = p_data_i;                // 8 bits if PARITY=0
          end
          else begin
            // MSB-first => store MSB in shift_reg_d[SHIFT_W-1]
            // If parity is used, it goes in the LSB or SHIFT_W-1?
            // We'll put it in the LSB if EXTRA_BIT=1
            if (EXTRA_BIT == 1) begin
              shift_reg_d[8:4] = {p_data_i[4:0],parity_bit};
              shift_reg_d[3:0] = p_data_i[8:5];
            end else
              shift_reg_d = p_data_i;
          end

          count_d = 0;
          state_d = ST_TX;
        end
      end

      // ST_TX: Shift bits out until SHIFT_W done
      ST_TX: begin
        // Only shift if s_ready_i & tx_en_i
        if (s_ready_i && tx_en_i) begin
          if (count_q == (SHIFT_W - 1)) begin
            // Done sending SHIFT_W bits
            state_d   = ST_RX;
            count_d   = 0;
          end
          else begin
            if (BIT_ORDER == 1) begin
              if (EXTRA_BIT == 1) begin
                // SHIFT left by 2 bits
                shift_reg_d[SHIFT_W-1:2] = shift_reg_q[SHIFT_W-3:0];
                shift_reg_d[1:0]         = 2'b00;
                count_d                  = count_q + 2;
              end
              else begin
                // Normal MSB-first => shift left by 1
                shift_reg_d = {shift_reg_q[SHIFT_W-2:0], 1'b0};
                count_d     = count_q + 1;
              end
            end
            else begin
              // LSB-first => shift right by 1 (no bug)
              shift_reg_d = {1'b0, shift_reg_q[SHIFT_W-1:1]};
              count_d     = count_q + 1;
            end
          end
        end
      end

      default: begin
        state_d = ST_RX; // safe fallback
      end
    endcase
  end

  // Outputs
  assign s_valid_o = (state_q == ST_TX);

  // LSB-first => s_data_o = shift_reg_q[0]
  // MSB-first => s_data_o = shift_reg_q[SHIFT_W-1]
  assign s_data_o  = (BIT_ORDER == 0) ? shift_reg_q[0] : shift_reg_q[SHIFT_W-1];

  assign p_ready_o = (state_q == ST_RX);

endmodule

