module async_fifo #(
    parameter DATA_WIDTH = 8,
    parameter DEPTH = 32
)(
    input wire w_clk,
    input wire w_rst,
    input wire w_inc,
    input wire w_data,
    input r_clk,
    input wire r_rst,
    input wire r_inc,
    output reg w_full,
    output reg r_empty,
    output reg [DATA_WIDTH-1:0] r_data,
    output reg [DATA_WIDTH-1:0] w_full_reg,
    output reg [DATA_WIDTH-1:0] r_empty_reg
);

    // Synchronize signals across clock domains
    always @(posedge w_clk or negedge w_rst) begin
        if (w_rst) begin
            w_full <= 1'b0;
            r_empty <= 1'b1;
            w_full_reg <= 1'b0;
            r_empty_reg <= 1'b1;
        end else begin
            // ...
        end
    end

    // Declare internal signals
    reg [DATA_WIDTH-1:0] data;
    reg wr_pos, rd_pos;
    reg [1:0] wr_gray, rd_gray;

    // Initialize counters
    initial begin
        wr_pos = 32'd0;
        rd_pos = 32'd0;
    end

    // Write process
    always @(posedge w_clk or negedge w_rst) begin
        if (w_rst) begin
            wr_pos <= 32'd0;
            rd_pos <= 32'd0;
            w_full_reg <= 1'b0;
            r_empty_reg <= 1'b1;
        end else begin
            if (w_inc) begin
                // Check if FIFO is full
                if (wr_pos == rd_pos) begin
                    w_full_reg <= 1'b1;
                end else if (wr_pos == rd_pos + 1) begin
                    // overflow? but we don't need that
                end else if (wr_pos == rd_pos - 1) begin
                    // underflow? not needed
                end else begin
                    // just shift
                    data <= data >> 1;
                    wr_pos <= wr_pos + 1;
                    rd_pos <= rd_pos + 1;
                end
            end
            if (w_data) begin
                data <= w_data;
            end
        end
    end

    // Read process
    always @(posedge r_clk or negedge r_rst) begin
        if (r_rst) begin
            rd_pos <= 32'd0;
            w_full_reg <= 1'b0;
            r_empty_reg <= 1'b1;
        end else begin
            if (r_inc) begin
                if (rd_pos == wr_pos) begin
                    r_empty_reg <= 1'b0;
                end else if (rd_pos == wr_pos + 1) begin
                    // underflow?
                end else if (rd_pos == wr_pos - 1) begin
                    // overflow?
                end else begin
                    data <= data << 1;
                    rd_pos <= rd_pos - 1;
                    w_full_reg <= 1'b0;
                end
            end
            if (r_data) begin
                r_data <= data;
            end
        end
    end

    // Outputs
    assign w_full = w_full_reg;
    assign r_empty = r_empty_reg;
    assign r_data = data;
    assign w_full_reg = w_full;
    assign r_empty_reg = r_empty;

endmodule

input.rtl/ping_pong_fifo_2_axi_stream.sv:
module ping_pong_fifo_2_axi_stream #( 
    parameter DATA_WIDTH = 32
)(
    input  logic                                 rst,

    // Ping Pong FIFO Read Interface
    input  logic                                 i_block_fifo_rdy,
    output logic                                 o_block_fifo_act,
    input  logic [23:0]                          i_block_fifo_size,
    input  logic [(DATA_WIDTH + 1) - 1:0]        i_block_fifo_data,
    output logic                                 o_block_fifo_stb,
    input  logic [3:0]                           i_axi_user,

    // AXI Stream Output
    input  logic                                 i_axi_clk,
    output logic [3:0]                           o_axi_user,
    input  logic                                 i_axi_ready,
    output logic [DATA_WIDTH - 1:0]              o_axi_data,
    output logic                                 o_axi_last,
    output logic                                 o_axi_valid
);

    // Internal Registers
    logic [23:0] block_size_reg;
    logic [23:0] data_count;
    logic        fifo_active;
    logic        data_valid;

    typedef enum logic [1:0] {
        IDLE,
        READ_FIFO,
        SEND_AXI
    } state_t;

    state_t current_state, next_state;

    always_ff @(posedge i_axi_clk or posedge rst) begin
        if (rst) begin
            current_state      <= IDLE;
            block_size_reg     <= 24'd0;
            data_count         <= 24'd0;
            fifo_active        <= 1'b0;
            o_block_fifo_act   <= 1'b0;
            o_block_fifo_stb   <= 1'b0;
            o_axi_valid        <= 1'b0;
            o_axi_data         <= {DATA_WIDTH{1'b0}};
            o_axi_last         <= 1'b0;
            o_axi_user         <= 4'd0;
        end else begin
            current_state      <= next_state;
            o_block_fifo_act   <= 1'b0;
            o_block_fifo_stb   <= 1'b0;
            o_axi_valid        <= 1'b0;
            o_axi_last         <= 1'b0;

            case (current_state)
                IDLE: begin
                    if (i_block_fifo_rdy) begin
                        o_block_fifo_act <= 1'b1; 
                        block_size_reg    <= i_block_fifo_size;
                        fifo_active       <= 1'b1;
                        data_count        <= 24'd0;
                        next_state        <= READ_FIFO;
                    end else begin
                        next_state <= IDLE;
                    end
                end

                READ_FIFO: begin
                    if (fifo_active && i_block_fifo_rdy) begin
                        o_block_fifo_stb <= 1'b1; 
                        data_count       <= data_count + 24'd1;
                        next_state       <= SEND_AXI;
                    end else begin
                        next_state <= READ_FIFO;
                    end
                end

                SEND_AXI: begin
                    if (fifo_active && i_axi_ready) begin
                        o_axi_valid  <= 1'b1;
                        o_axi_data   <= i_block_fifo_data[DATA_WIDTH-1:0];
                        o_axi_user   <= i_axi_user;

                        if (data_count + 24'd1 >= block_size_reg) begin
                            o_axi_last <= 1'b1;
                            fifo_active <= 1'b0; 
                            next_state  <= IDLE;
                        end else begin
                            next_state <= READ_FIFO;
                        end
                    end else begin
                        next_state <= SEND_AXI;
                    end
                end

                default: next_state <= IDLE;
            endcase
        end
    end

endmodule

output.rtl/ping_pong_fifo_2_axi_stream.sv:
module ping_pong_fifo_2_axi_stream #(
    parameter DATA_WIDTH = 32
) (
    input  logic                                 rst,

    // Ping Pong FIFO Read Interface
    input  logic                                 i_block_fifo_rdy,
    output logic                                 o_block_fifo_act,
    input  logic [23:0]                          i_block_fifo_size,
    input  logic [(DATA_WIDTH + 1) - 1:0]        i_block_fifo_data,
    output logic                                 o_block_fifo_stb,
    input  logic [3:0]                           i_axi_user,

    // AXI Stream Output
    input  logic                                 i_axi_clk,
    output logic [3:0]                           o_axi_user,
    input  logic                                 i_axi_ready,
    output logic [DATA_WIDTH - 1:0]              o_axi_data,
    output logic                                 o_axi_last,
    output logic                                 o_axi_valid
);

    // Internal Registers
    logic [23:0] block_size_reg;
    logic [23:0] data_count;
    logic        fifo_active;
    logic        data_valid;
    logic        i_flush, i_pause;
    logic [1:0] next_state;

    typedef enum logic [1:0] {
        IDLE,
        READ_FIFO,
        SEND_AXI,
        PAUSE
    } state_t;

    state_t current_state, next_state;

    always_ff @(posedge i_axi_clk or posedge rst) begin
        if (rst) begin
            current_state      <= IDLE;
            block_size_reg     <= 24'd0;
            data_count         <= 24'd0;
            fifo_active        <= 1'b0;
            o_block_fifo_act   <= 1'b0;
            o_block_fifo_stb   <= 1'b0;
            o_axi_valid        <= 1'b0;
            o_axi_last         <= 1'b0;
            o_axi_user         <= 4'd0;
        end else begin
            current_state      <= next_state;

            // Flush: reset everything and stop everything
            if (i_flush) begin
                current_state   <= IDLE;
                block_size_reg   <= 24'd0;
                data_count       <= 24'd0;
                fifo_active      <= 1'b0;
                o_block_fifo_act <= 1'b0;
                o_block_fifo_stb <= 1'b0;
                o_axi_valid      <= 1'b0;
                o_axi_last       <= 1'b0;
                o_axi_user       <= 4'd0;
            end

            // Pause: suspend AXI data but keep state
            if (i_pause) begin
                current_state   <= PAUSE;
                next_state      <= IDLE;  // Resume from idle after pause
            end

            // Normal states
            case (current_state)
                IDLE: begin
                    if (i_block_fifo_rdy) begin
                        o_block_fifo_act <= 1'b1;
                        block_size_reg    <= i_block_fifo_size;
                        fifo_active       <= 1'b1;
                        data_count        <= 24'd0;
                        next_state        <= READ_FIFO;
                    end else begin
                        next_state        <= IDLE;
                    end
                end

                READ_FIFO: begin
                    if (fifo_active && i_block_fifo_rdy) begin
                        o_block_fifo_stb <= 1'b1;
                        data_count       <= data_count + 24'd1;
                        next_state       <= SEND_AXI;
                    end else begin
                        next_state        <= READ_FIFO;
                    end
                end

                SEND_AXI: begin
                    if (fifo_active && i_axi_ready) begin
                        o_axi_valid  <= 1'b1;
                        o_axi_data   <= i_block_fifo_data[DATA_WIDTH-1:0];
                        o_axi_user   <= i_axi_user;

                        if (data_count + 24'd1 >= block_size_reg) begin
                            o_axi_last <= 1'b1;
                            fifo_active <= 1'b0;
                            next_state  <= IDLE;
                        end else begin
                            next_state  <= READ_FIFO;
                        end
                    end else begin
                        next_state  <= SEND_AXI;
                    end
                end

                PAUSE: begin
                    // No action – just stay in PAUSE
                    next_state  <= IDLE;
                end

                default: next_state <= IDLE;
            endcase
        end
    end

endmodule

output.rtl/FILO_RTL.sv:
module FILO_RTL #(
    parameter DATA_WIDTH = 8,
    parameter FILO_DEPTH = 16
)(
    input wire clk,
    input wire reset,
    input wire push,
    input wire pop,
    input wire data_in,
    output reg data_out,
    output reg full,
    output reg empty
);

reg [DATA_WIDTH - 1:0] data;
reg [0:0] top;

initial begin
    top = 0;
    data = 0;
    empty = 1;
    full = 0;
end

always @(posedge clk or posedge reset) begin
    if (reset) begin
        data = 0;
        top = 0;
        empty = 1;
        full = 0;
    end else begin
        case (full)
            'b0: begin
                if (push) begin
                    data[top] = data_in;
                    top = (top + 1) mod FILO_DEPTH;
                    empty = 1;
                    full = 0;
                end
            end
            'b1: begin
                if (pop) begin
                    data_out = data[top];
                    top = (top + 1) mod FILO_DEPTH;
                    full = 0;
                    empty = 1;
                end
            end
        endcase
    end
end

endmodule

input.rtl/FILO_RTL.sv:
module FILO_RTL #(
    parameter DATA_WIDTH = 8,  // Width of the data entries
    parameter FILO_DEPTH = 16  // Depth of the FILO buffer
) (
    input  wire                  clk,       // Clock signal
    input  wire                  reset,     // Asynchronous reset signal
    input  wire                  push,      // Push control signal
    input  wire                  pop,       // Pop control signal
    input  wire [DATA_WIDTH-1:0] data_in,   // Data input
    output reg  [DATA_WIDTH-1:0] data_out,  // Data output
    output reg                   full,      // Full status signal
    output reg                   empty      // Empty status signal
);


  reg [DATA_WIDTH-1:0] memory[FILO_DEPTH-1:0];  
  reg [$clog2(FILO_DEPTH):0] top;  

  reg feedthrough_valid;
  reg [DATA_WIDTH-1:0] feedthrough_data;


  always @(posedge clk or posedge reset) begin
    if (reset) begin
      top <= 0;
      empty <= 1;
      full <= 0;
      feedthrough_valid <= 0;
      data_out <= 0;  
    end else begin

      if (push && pop && empty) begin
        data_out <= data_in; 
        feedthrough_data <= data_in;
        feedthrough_valid <= 1;
      end else begin

        if (push && !full) begin
          memory[top] <= data_in;  
          top <= top + 1;  
          feedthrough_valid <= 0;
        end

        if (pop && !empty) begin
          if (feedthrough_valid) begin
            data_out <= feedthrough_data;  
            feedthrough_valid <= 0;
          end else begin
            top <= top; 
            data_out <= memory[top-1]; 
          end
        end
      end

      empty <= (top == 0);
      full  <= (top == FILO_DEPTH);  
    end
  end
endmodule

