module hamming_code_receiver(input [7:0] data_in, output reg [3:0] data_out);

    localint c1, c2, c3;

    c1 = data_in[4] ^ data_in[5] ^ data_in[6] ^ data_in[7];
    c2 = data_in[2] ^ data_in[3] ^ data_in[6] ^ data_in[7];
