    assign tag_0_data = ram_t0_data;
    assign tag_1_data = ram_t1_data;

    always @(*) begin
        data_0_out = tag_0_data;
        data_1_out = tag_1_data;

        assign data_0_valid = tag_0_data[TAG_BITS-1:0] == 1'b1;
        assign data_1_valid = tag_1_data[TAG_BITS-1:0] == 1'b1;

