module load_store_unit #(
    parameter CLK_FREQ = 50,
    parameter DATA_WIDTH = 32
)(
    input wire clk,
    input wire rst_n,
    input wire ex_if_req_i,
    input wire ex_if_we_i,
    input wire ex_if_type_i,
    input wire ex_if_wdata_i,
    input wire ex_if_addr_base_i,
    input wire ex_if_addr_offset_i,
    input wire ex_if_ready_o,
    input wire dmem_req_o,
    input wire dmem_gnt_i,
    input wire dmem_req_addr_o,
    input wire dmem_req_we_o,
    input wire dmem_req_be_o[3:0],
    input wire dmem_req_wdata_o,
    input wire dmem_rvalid_i,
    input wire dmem_rsp_rdata_i,
    output reg ex_if_ready_o,
    output reg wb_if_rvalid_o,
    output reg [31:0] wb_if_rdata_o,
    output reg [31:0] wb_if_raddr_o,
    output reg [3:0] wb_if_rdata_wdata,
    output reg [3:0] wb_if_raddr_write
);

// Reset logic
always @(*) begin
    if (rst_n) begin
        ex_if_ready_o <= 1'b1;
        wb_if_rvalid_o <= 1'b0;
        wb_if_rdata_o <= 0;
        wb_if_raddr_o <= 0;
        wb_if_raddr_offset_o <= 0;
        wb_if_rdata_wdata <= 0;
        wb_if_raddr_write <= 1'b0;
    end
end

// Execute stage interface
always @(posedge clk or posedge rst_n) begin
    if (rst_n) begin
        ex_if_ready_o <= 1'b1;
        wb_if_rvalid_o <= 1'b0;
        wb_if_rdata_o <= 0;
        wb_if_raddr_o <= 0;
        wb_if_raddr_offset_o <= 0;
        wb_if_rdata_wdata <= 0;
        wb_if_raddr_write <= 1'b0;
    end else begin
        if (ex_if_ready_o && ex_if_req_i && !ex_if_we_i) begin
            if (ex_if_addr_base_i[31:0] == ex_if_addr_offset_i[31:0] + ex_if_addr_offset_i) begin
                if (ex_if_addr_offset_i[3:1] == 0) begin
                    // byte access
                    dmem_req_wdata_o <= ex_if_wdata_i;
                    dmem_req_be_o[3:0] <= ex_if_be_mask;
                    dmem_req_addr_o <= ex_if_addr_base_i + ex_if_addr_offset_i;
                    dmem_req_wdata_o <= ex_if_wdata_i;
                    dmem_req_we_o <= 1'b1;
                end else begin
                    // halfword
                    dmem_req_wdata_o <= ex_if_wdata_i[1:0];
                    dmem_req_be_o[3:2] <= ex_if_be_mask;
                    dmem_req_addr_o <= ex_if_addr_base_i + ex_if_addr_offset_i;
                    dmem_req_wdata_o <= ex_if_wdata_i[1:0];
                    dmem_req_be_o[2:1] <= ex_if_be_mask[1:0];
                    dmem_req_addr_o <= ex_if_addr_base_i + ex_if_addr_offset_i;
                end
            end else begin
                // misaligned
                dmem_req_o <= 1'b0;
                dmem_req_we_o <= 1'b0;
            end
        end else begin
            dmem_req_o <= 1'b0;
            dmem_req_we_o <= 1'b0;
        end
    end
end

// Writeback stage
always @(posedge clk or posedge rst_n) begin
    if (rst_n) begin
        wb_if_rvalid_o <= 1'b0;
        wb_if_rdata_o <= 0;
        wb_if_raddr_o <= 0;
        wb_if_raddr_offset_o <= 0;
        wb_if_rdata_wdata <= 0;
        wb_if_raddr_write <= 1'b0;
    end else begin
        if (wb_if_rvalid_o && wb_if_raddr_o == ex_if_addr_base_i) begin
            wb_if_rdata_o <= dmem_rsp_rdata_i;
            wb_if_raddr_o <= ex_if_addr_base_i;
            wb_if_raddr_offset_o <= ex_if_addr_offset_i;
            wb_if_rdata_wdata <= dmem_rsp_rdata_i;
            wb_if_raddr_write <= 1'b0;
        end else begin
            wb_if_rvalid_o <= 1'b0;
            wb_if_rdata_o <= 0;
            wb_if_raddr_o <= 0;
            wb_if_raddr_offset_o <= 0;
            wb_if_rdata_wdata <= 0;
            wb_if_raddr_write <= 1'b0;
        end
    end
end

endmodule

input.rtl/load_store_unit.sv:
module load_store_unit (
    input  logic                 clk,
    input  logic                 rst_n,

    // EX stage interface
    input  logic                 ex_if_req_i,           // LSU request
    input  logic                 ex_if_we_i,            // Write enable: 0 (load), 1 (store)
    input  logic     [ 1:0]      ex_if_type_i,          // Data type: 0x2 (word), 0x1 (halfword), 0x0 (byte)
    input  logic     [31:0]      ex_if_wdata_i,         // Data to write to memory
    input  logic     [31:0]      ex_if_addr_base_i,     // Base address
    input  logic     [31:0]      ex_if_addr_offset_i,   // Offset address
    output logic                 ex_if_ready_o    ,

    // Writeback stage interface
    output logic     [31:0]      wb_if_rdata_o,         // Requested data
    output logic                 wb_if_rvalid_o,        // Requested data valid

    // Data memory (DMEM) interface
    output logic                 dmem_req_o,
    input  logic                 dmem_gnt_i,
    output logic     [31:0]      dmem_req_addr_o,
    output logic                 dmem_req_we_o,
    output logic     [ 3:0]      dmem_req_be_o,
    output logic     [31:0]      dmem_req_wdata_o,
    input  logic     [31:0]      dmem_rsp_rdata_i,
    input  logic                 dmem_rvalid_i
    );

  // Internal signals
  logic ex_req_fire;
  logic dmem_req_we_q;
  logic [31:0] data_addr_int;
  logic misaligned_addr;
  logic [3:0] dmem_be, dmem_req_be_q;

  logic busy_q;  // Sticky busy bit: Set with EX req and cleared with DMEM response
  logic dmem_req_q ;




  logic [31:0] dmem_req_wdata_q;
  logic [31:0] dmem_req_addr_q;

  logic [31:0] wb_if_rdata_q;
  logic wb_if_rvalid_q;

  // Address calculation
  assign data_addr_int = ex_if_addr_base_i + ex_if_addr_offset_i;

  // EX request fire condition
  assign ex_req_fire = ex_if_req_i && !busy_q && !misaligned_addr;
  assign ex_if_ready_o = !busy_q;

  ///////////////////////////////// Byte Enable Generation ////////////////////////////////
  always_comb begin
    misaligned_addr = 1'b0;
    dmem_be = 4'b0000;
    case (ex_if_type_i)  // 0x2 (word), 0x1 (halfword), 0x0 (byte)
      2'b00: begin  // Writing a byte
          case (data_addr_int[1:0])
            2'b00:   dmem_be = 4'b0001;
            2'b01:   dmem_be = 4'b0010;
            2'b10:   dmem_be = 4'b0100;
            2'b11:   dmem_be = 4'b1000;
            default: dmem_be = 4'b0000;
          endcase
      end

      2'b01: begin  // Writing a half-word
          case (data_addr_int[1:0])
            2'b00:   dmem_be = 4'b0011;
            2'b10:   dmem_be = 4'b1100;
            default: begin
                dmem_be = 4'b0000;
                misaligned_addr = 1'b1;
            end
          endcase
      end

      2'b10: begin  // Writing a word
          case (data_addr_int[1:0])
            2'b00:   dmem_be = 4'b1111;
            default: begin
                dmem_be = 4'b0000;
                misaligned_addr = 1'b1;
            end
          endcase
      end
      default: begin
          dmem_be = 4'b0000;
          misaligned_addr = 1'b1;
      end 
    endcase
  end


  ///////////////////////////////// dmem_req ////////////////////////////////
  always_ff @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
      dmem_req_q <= 1'b0;
      dmem_req_addr_q <= '0;
      dmem_req_we_q <= '0 ;
      dmem_req_be_q <= '0 ;
      dmem_req_wdata_q <= '0 ;
    end else if (ex_req_fire) begin
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= ex_if_we_i;
      dmem_req_be_q <= dmem_be ;
      dmem_req_wdata_q <= ex_if_wdata_i ;
    end else if (dmem_req_q && dmem_gnt_i) begin
      dmem_req_q <= 1'b0;  // request granted
      dmem_req_addr_q <= '0 ;
      dmem_req_we_q <= '0 ;
      dmem_req_be_q <= '0 ;
      dmem_req_wdata_q <= '0 ;
    end
  end


  ///////////////////////////////// DMEM Request Interface ////////////////////////////////
  always_comb begin : dmem_req
    dmem_req_o        = dmem_req_q;
    dmem_req_addr_o   = dmem_req_addr_q;
    dmem_req_we_o     = dmem_req_we_q;
    dmem_req_be_o     = dmem_req_be_q;
    dmem_req_wdata_o  = dmem_req_wdata_q;
  end

  ///////////////////////////////// Read Response Handling ////////////////////////////////
