output.rtl/packet_controller.sv:
module packet_controller (
    input clk,
    input rst,
    input rx_valid_i,
    input rx_data_8_i [7:0],
    input tx_done_tick_i,
    output reg tx_start_o,
    output reg [7:0] tx_data_8_o
);

// Internal state machine registers
reg [3:0] state;
reg [3:0] next_state;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        state <= 0;
        next_state <= 0;
    end else begin
        case (state)
            0: // S_IDLE
                if (rx_valid_i) begin
                    state <= 1;
                end
                next_state <= 0;
            end
            1: // S_GOT_8_BYTES
                if (rx_data_8_i[7:0] == {16'b10100000, 16'b10000000, 16'b00000000, 16'b00000000}) begin
                    // valid header? Actually the spec says 16'hBACD. So we need to check that.
                    // But the example above is 16 bits; we can assume the data is 16 bits.
                    state <= 2;
                end else begin
                    state <= 0;
                end
            end
            2: // S_RECV_CHECKSUM
                if (rx_data_8_i[7:0] == {16'b10100000, 16'b10000000, 16'b00000000, 16'b00000000}) begin
                    state <= 3;
                end else begin
                    state <= 0;
                end
            end
            3: // S_BUILD_RESPONSE
                if (tx_done_tick_i) begin
                    tx_start_o <= 1;
                    tx_data_8_o[0] <= 1'b0;
                    next_state <= 4;
                end else begin
                    next_state <= 3;
                end
            end
            4: // S_SEND_FIRST_BYTE
                if (tx_done_tick_i) begin
                    tx_start_o <= 1;
                    tx_data_8_o[0] <= rx_data_8_i[7];
                    tx_data_8_o[1] <= rx_data_8_i[6];
                    tx_data_8_o[2] <= rx_data_8_i[5];
                    tx_data_8_o[3] <= rx_data_8_i[4];
                    next_state <= 5;
                end else begin
                    next_state <= 4;
                end
            end
            5: // S_RESPONSE_READY
                if (tx_done_tick_i) begin
                    tx_done_tick_i <= 1;
                    next_state <= 6;
                end else begin
                    next_state <= 5;
                end
            end
            6: // S_RESPONSE_READY
                if (tx_done_tick_i) begin
                    tx_done_tick_i <= 0;
                    state <= 0;
                end else begin
                    state <= 6;
                end
        endcase
    end
endalways

assign tx_start_o = tx_start_o;
assign tx_data_8_o = tx_data_8_o;

endmodule

output.rtl/palindrome_detect.sv:
module palindrome_detect #(
    parameter N=3
) (
    input clk,
    input reset,
    input bit_stream,
    output reg palindrome_detected
);

    reg [N-1:0] first_bit, second_bit, third_bit;
    reg [N-1:0] current_bit;
    reg [N-1:0] temp;

    initial begin
        first_bit <= 0;
        second_bit <= 0;
        third_bit <= 0;
        palindrome_detected <= 0;
    end

    always @(posedge clk) begin
        if (reset) begin
            first_bit <= 0;
            second_bit <= 0;
            third_bit <= 0;
            palindrome_detected <= 0;
        end else begin
            current_bit <= bit_stream;
            if (current_bit == first_bit) begin
                palindrome_detected <= 1;
            end else begin
                palindrome_detected <= 0;
            end
            second_bit <= first_bit;
            first_bit <= second_bit;
            third_bit <= current_bit;
        end
    end

endmodule

output.rtl/password_generator.sv:
module password_generator #(
    parameter WIDTH = 4  
) (
    input logic clk,
    input logic reset,
    output logic [(WIDTH*8)-1:0] password 
);

  logic [7:0] char_array[WIDTH-1:0];
  logic [7:0] counter;
  logic [1:0] char_type;

  int i;

  initial begin
    char_array[0:WIDTH-1] = 0;
  end

  always @(posedge clk) begin
    if (reset) begin
      counter <= 0;
      password <= "0" * WIDTH;
    end else begin
      counter = counter + 1;
      for (i = 0; i < WIDTH; i = i + 1) begin
        char_type = $urandom_range(0, 3);
        case (char_type)
          0: begin
            password[i] = ((counter + char_array[(i+1)%WIDTH]) % 26) + 8'd97;
          end
          1: begin
            password[i] = ((counter + i) % 26) + 8'd65;
          end
          2: begin
            password[i] = ((counter + char_array[(i+WIDTH-1)%WIDTH]) % 14) + 8'd33;
          end
          3: begin
            password[i] = ((counter + i) % 10) + 8'd48;
          end
        endcase
      end
    end
  end

endmodule

input.rtl/perceptron_gates.sv:
module perceptron_gates (
   input  logic clk,// Posedge clock
   input  logic rst_n,// Negedge reset
   input  logic signed [3:0] x1, // First Input of the Perceptron
   input  logic signed [3:0] x2, // Second Input of the Perceptron
   input  logic learning_rate, // Learning rate (alpha)
   input  logic signed [3:0] threshold, // Threshold value
   input  logic [1:0] gate_select, // Gate selection for target values
   output logic signed [3:0] percep_w1, // Trained Weight 1 
   output logic signed [3:0] percep_w2, // Trained Weight 2
   output logic signed [3:0] percep_bias, // Trained Bias
   output logic [3:0] present_addr, // Current address in microcode ROM
   output logic stop, // Condition to indicate no learning has occurred(i.e. no weight change between iterations)
   output logic [2:0] input_index,// Vector to track the selection of target for a given input combination for a gate
   output logic signed [3:0] y_in, // Calculated Response
   output logic signed [3:0] y, // Calculated Response obtained by comparing y_in against a threshold value
   output logic signed [3:0] prev_percep_wt_1,//Value of Weight 1 during a previous iteration
   output logic signed [3:0] prev_percep_wt_2,//Value of Weight 2 during a previous iteration
   output logic signed [3:0] prev_percep_bias // Value of Bias during a previous iteration
);

   logic [15:0] microcode_rom [0:5];
   logic [3:0]  next_addr;
   logic [3:0]  train_action;
   logic [3:0]  microcode_addr;
   logic [15:0] microinstruction;
   logic signed [3:0] t1, t2, t3, t4;

   gate_target dut (
       .gate_select(gate_select),
       .o_1(t1),
       .o_2(t2),
       .o_3(t3),
       .o_4(t4)
   );

   logic signed [3:0] percep_wt_1_reg;
   logic signed [3:0] percep_wt_2_reg;
   logic signed [3:0] percep_bias_reg;


   logic signed [3:0] target;
   logic signed [3:0] prev_wt1_update;
   logic signed [3:0] prev_wt2_update;
   logic signed [3:0] prev_bias_update;

   logic signed [3:0] wt1_update;
   logic signed [3:0] wt2_update;
   logic signed [3:0] bias_update;
   logic [7:0] epoch_counter;

   assign  prev_percep_wt_1 = prev_wt1_update;
   assign  prev_percep_wt_2 = prev_wt2_update;
   assign  prev_percep_bias = prev_bias_update;

   initial begin 
      microcode_rom[0] = 16'b0001_0000_0000_0000; 
      microcode_rom[1] = 16'b0010_0001_0000_0000; 
      microcode_rom[2] = 16'b0011_0010_0000_0000; 
      microcode_rom[3] = 16'b0100_0011_0000_0000; 
      microcode_rom[4] = 16'b0101_0100_0000_0000; 
      microcode_rom[5] = 16'b0000_0101_0000_0000; 
   end  

   always@(*) begin
      microinstruction = microcode_rom[microcode_addr];
      next_addr        = microinstruction[15:12];
      train_action     = microinstruction[11:8];
   end

   always_ff @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         present_addr    <= 4'd0;
         microcode_addr  <= 4'd0;
         percep_wt_1_reg <= 4'd0;
         percep_wt_2_reg <= 4'd0;
         percep_bias_reg <= 4'd0;
         input_index     <= 2'd0;
         stop            <= 1'b0;
      end else begin
         present_addr    <= next_addr;
         microcode_addr  <= present_addr;
      end
   end

   always_comb begin
      case (train_action)
         4'd0:  begin 
                   percep_wt_1_reg = 4'd0;
                   percep_wt_2_reg = 4'd0;
                   percep_bias_reg = 4'd0;
                   stop = 1'b0;
                   next_addr = next_addr + 4'd0;
                   y_in = 4'd0;
                   y    = 4'd0;
                   prev_wt1_update = 4'd0;
                   prev_wt2_update = 4'd0;
                   prev_bias_update = 4'd0;
                   input_index = 0;
                   target = 0;
                   wt1_update = 0;
                   wt2_update = 0;
                   bias_update = 0;
                   epoch_counter = 0;
                end
         4'd1 : begin 
                   y_in = percep_bias_reg + (x1 * percep_wt_1_reg) + (x2 * percep_wt_2_reg); 
                   if (y_in > threshold)
                      y = 4'd1;
                   else if (y_in >= -threshold && y_in <= threshold)
                      y = 4'd0;
                   else
                      y = -4'd1;

                   percep_wt_1_reg  = percep_wt_1_reg  + 4'd0;
                   percep_wt_2_reg  = percep_wt_2_reg  + 4'd0;
                   percep_bias_reg  = percep_bias_reg  + 4'd0;
                   prev_wt1_update  = prev_wt1_update  + 4'd0;
                   prev_wt2_update  = prev_wt2_update  + 4'd0;
                   prev_bias_update = prev_bias_update + 4'd0;
                   input_index = input_index + 0;
                   next_addr = next_addr + 4'd0;
                   stop = stop + 1'b0;
                   target = target + 4'd0;
                   wt1_update = wt1_update + 4'd0 ;
                   wt2_update = wt2_update + 4'd0 ;
                   bias_update = bias_update + 4'd0 ;
                   epoch_counter = epoch_counter + 0;
                end
         4'd2 : begin
                   if(input_index == 0)
                        target = t1;
                   else if(input_index == 1)
                        target = t2;
                   else if(input_index == 2)
                        target = t3;
                   else if(input_index == 3)
                        target = t4;
                   else begin
                        input_index = 0;
                        target = 0;
                   end
                   stop = stop + 1'b0;
                   input_index = input_index + 0;
                   next_addr = next_addr + 4'd0;
                   target = target + 4'd0;
                   prev_wt1_update  = prev_wt1_update  + 4'd0;
                   prev_wt2_update  = prev_wt2_update  + 4'd0;
                   prev_bias_update = prev_bias_update + 4'd0;

                   percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                   percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                   percep_bias_reg = percep_bias_reg + 4'd0;
                   y_in = y_in + 4'd0;
                   y = y + 4'd0;
                   wt1_update = wt1_update + 4'd0 ;
                   wt2_update = wt2_update + 4'd0 ;
                   bias_update = bias_update + 4'd0 ;
                   epoch_counter = epoch_counter + 0;
                end
         4'd3 : begin
                   if (y != target) begin
                        wt1_update = learning_rate * x1 * target ;
                        wt2_update = learning_rate * x2 * target ;
                        bias_update = learning_rate * target ; 
                    end else begin
                        wt1_update = 0 ;
                        wt2_update = 0 ;
                        bias_update = 0 ;     
                    end    
                    percep_wt_1_reg = percep_wt_1_reg + wt1_update;
                    percep_wt_2_reg = percep_wt_2_reg + wt2_update;
                    percep_bias_reg = percep_bias_reg + bias_update;
                    prev_wt1_update  = prev_wt1_update  + 4'd0;
                    prev_wt2_update  = prev_wt2_update  + 4'd0;
                    prev_bias_update = prev_bias_update + 4'd0;
                    y_in = y_in + 4'd0;
                    y = y + 4'd0;
                    stop = stop + 1'b0;
                    input_index = input_index + 0;
                    next_addr = next_addr + 4'd0;
                    target = target + 4'd0;
                    epoch_counter = epoch_counter + 0;
                end
         4'd4 : begin
                  if ((prev_wt1_update == wt1_update) & (prev_wt2_update == wt2_update) & (input_index == 4'd3)) begin 
                          epoch_counter = 0;
                          stop = 1'b1; 
                          input_index = 0;
                          next_addr = 4'd0;
                          percep_wt_1_reg = 0;
                          percep_wt_2_reg = 0;
                          percep_bias_reg = 0;
                          prev_wt1_update =  0;
                          prev_wt2_update =  0;
                          prev_bias_update = 0;
                          y_in = 0;
                          y = 0;
                          target = 0;
                          wt1_update = 0 ;
                          wt2_update = 0 ;
                          bias_update = 0 ;
                  end else begin
                          stop = 1'b0; 
