        o_result <= 8'b0;
    else
        if (i_key_in == p_key) begin
            case (i_opcode)
                4'b000: o_result = i_operand_a + i_operand_b;
                4'b001: o_result = i_operand_a - i_operand_b;
                4'b010: o_result = i_operand_a * i_operand_b;
                4'b011: o_result = i_operand_a & i_operand_b;
                4'b100: o_result = i_operand_a | i_operand_b;
                4'b101: ~i_operand_a;
                4'b110: i_operand_a ^ i_operand_b;
                4'b111: ~(i_operand_a ^ i_operand_b);
            endcase
        end else
            o_result <= 8'b0;
end

endmodule

output.rtl/secure_read_write_bus_interface.v:
module secure_read_write_bus_interface (
    input wire i_addr,
    input wire i_data_in,
    input wire i_key_in,
    input wire i_read_write_enable,
    input wire i_capture_pulse,
    input wire i_reset_bar
);

    localparam PAD_WIDTH = 8;
    localparam ADDR_WIDTH = 8;

    reg [ADDR_WIDTH-1:0] addr;
    reg [PAD_WIDTH-1:0] data;
    reg [7:0] key;
    reg [7:0] internal_key = 8'hAA;
    reg [1:0] mode;
    reg [1:0] state;
    reg [1:0] next_state;
    reg o_data_out;
    reg o_error;

    // Reset the internal state
    always @(posedge i_capture_pulse) begin
        if (i_reset_bar) begin
            addr <= 32'b0;
            data <= 0;
            key <= 8'hAA;
            internal_key <= 8'hAA;
            mode <= 2'b00;
            state <= 2'b00;
            next_state <= 2'b00;
            o_data_out <= 0;
            o_error <= 0;
        end else
        // Operate normally
    end

    // Read operation
    always @(posedge i_capture_pulse) begin
        if (i_read_write_enable) begin
            if (i_key_in == internal_key) begin
                o_data_out <= i_data_in;
                o_error <= 0;
            else
                o_data_out <= 0;
                o_error <= 1;
            end
        end else
        o_data_out <= 0;
    end

    // Write operation
    always @(posedge i_capture_pulse) begin
        if (i_write_enable) { // Use read_write_enable for control
            if (i_key_in == internal_key) begin
                o_data_out <= 0;
                o_error <= 0;
            else
                o_data_out <= 0;
                o_error <= 1;
            end
        end else
        o_data_out <= 0;
    end

endmodule

output.rtl/secure_variable_timer.v:
module secure_variable_timer (
    input wire i_clk,
    input wire i_rst_n,
    input wire i_data_in,
    output reg [3:0] o_time_left,
    output reg o_processing,
    output reg o_completed,
    input wire i_ack
);

    reg [3:0] delay;
    reg [3:0] temp;
    reg clk_counter;
    reg o_processing_tmp;

    // --------- State Machine ----------
    localparam IDLE = 4'd0;
    localparam CONFIGURE = 4'd1;
    localparam COUNTING = 4'd2;
    localparam DONE = 4'd3;

    always @(posedge i_clk) begin
        if (i_rst_n) begin
            state <= IDLE;
            delay <= 0;
            o_time_left <= 4'd1000;
            o_processing <= 1'b0;
            o_completed <= 1'b0;
            return;
        end

        case (state)
            IDLE: begin
                if (i_data_in == "1101") begin
                    state <= CONFIGURE;
                end
            end

            CONFIGURE: begin
                if (i_data_in[3] == '1') begin
                    if (i_data_in[2] == '1') begin
                        if (i_data_in[1] == '1') begin
                            if (i_data_in[0] == '1') begin
                                state <= COUNTING;
                            end;
                        end else end;
                    end else end;
                end
            end

            COUNTING: begin
                clk_counter <= clk_counter + 1;
                if (clk_counter == delay[3:0] + 1) begin
                    o_completed <= 1'b1;
                    delay <= 0;
                    state <= DONE;
                end else begin
                    o_processing <= ~o_processing;
                    o_time_left <= o_time_left - 1;
                end
            end

            DONE: begin
                if (i_ack) begin
                    state <= IDLE;
                    o_completed <= 1'b0;
                end
            end
        endcase
    end

endmodule

