            IDLE: begin
                if (start)
                    next_state = SORTING;
            end
            SORTING: begin
                // Perform a single comparison and swap if needed
                if (val_j > val_j1) begin
                    array[j]   <= val_j1;
                    array[j+1] <= val_j;
                end

                // Update j
                if (j == N-2) begin
                    // One pass completed, increment i
                    j <= 0;
                    i <= i + 1;
                end else begin
                    j <= j + 1;
                end
            end
            DONE: begin
                // Sorting complete
                done <= 1;
                // Output the sorted data
                for (int m = 0; m < N; m = m + 1) begin
                    out_data[(m+1)*WIDTH-1 -: WIDTH] <= array[m];
                end
            end
            default: begin
            end
        endcase
    end

