module Bitstream(input  logic clk,rst_n,
                 input  logic enb,
                 input  logic rempty_in,
                 input  logic rinc_in,
                 input  logic [7:0] i_byte,
                 output logic o_bit,
                 output logic rempty_out,
                 output logic rinc_out);

    parameter IDLE  = 3'b000;
    parameter WaitR = 3'b001;
    parameter Ready = 3'b010;
    logic [1:0] curr_state,next_state;

    logic [0:7] byte_buf;
    logic [3:0] bp;
    logic rde;

    //FSM block

    always_ff @(posedge clk) begin
        if(!rst_n) curr_state <= IDLE;
        else curr_state <= next_state;
    end

    always_comb begin
        case(curr_state)
            IDLE: next_state = Ready;
            IDLE:begin
                if(enb)begin
                    next_state = WaitR;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
                else begin
                    next_state = IDLE;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
            end
            WaitR:begin
                if(rempty_in)begin
                    next_state = WaitR;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
                else begin
                    next_state = Ready;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b1;
                end
            end
            Ready:begin
                if(rde)begin
                    if(rempty_in)begin
                        next_state = WaitR;
                        rempty_out = 1'b1;
                        rinc_out   = 1'b0;
                    end
                    else begin
                        next_state = Ready;
                        rempty_out = 1'b1;
                        rinc_out   = 1'b1;
                    end
                end
                else begin
                    next_state = Ready;
                    rempty_out = 1'b0;
                    rinc_out   = 1'b0;
                end
            end
            default:begin
                next_state = IDLE;
                rempty_out = 1'b1;
                rinc_out   = 1'b0;
            end
        endcase
    end

    always @(posedge clk) begin
        if(rinc_out) 
           byte_buf <= i_byte[7:1];
    end

    always @(posedge clk) begin
        if(rinc_out) 
            bp <= 4'b0;
        else 
            if(rinc_in & ~rempty_out) 
               bp <= bp + 1'b1;
    end

    //Other comb logic

    assign rde = bp[3];
    assign o_bit = byte_buf[bp];

endmodule

output.rtl/Bitstream.sv:
module Bitstream(input logic clk, rst_n,
                 input  logic enb,
                 input  logic rempty_in,
                 input  logic rinc_in,
                 input  logic [7:0] i_byte,
                 output logic o_bit,
                 output logic rempty_out,
                 output logic rinc_out);

    parameter IDLE  = 3'b000;
    parameter WaitR = 3'b001;
    parameter Ready = 3'b010;
    logic [1:0] curr_state, next_state;

    logic [0:7] byte_buf;
    logic [3:0] bp;
    logic rde;

    always_ff @(posedge clk) begin
        if (!rst_n) curr_state <= IDLE;
        else curr_state <= next_state;
    end

    always_comb begin
        case (curr_state)
            IDLE:   next_state = Ready;
            WAITR:  begin
                if (rempty_in) next_state = WaitR;
                else      next_state = Ready;
            end
            READY:  begin
                if (rde) begin
                    if (rempty_in) next_state = WaitR;
                    else      next_state = Ready;
                end
                default: next_state = IDLE;
            end
        endcase
    end

    always @(posedge clk) begin
        if (rinc_out)  o_bit = byte_buf[bp];
        else if (rinc_in & ~rempty_out) bp <= bp + 1'b1;
    end

    assign o_bit = byte_buf[bp];
endmodule

input.rtl/square_root.sv:
module square_root #(parameter WIDTH = 16) (
    input  wire [WIDTH-1:0] num,       
    output reg  [WIDTH/2-1:0] root     
);
    reg [WIDTH-1:0] remainder,square;         
    reg [WIDTH/2-1:0] test_bit, temp_square;        
    integer i,j;

    always @(*) 
    begin
        remainder = num;               
        root = 0;                      
        temp_square = 0;


        for (i = WIDTH/2-1; i >= 0; i = i - 1) 
        begin
            test_bit = 1'b1 << i;      
            temp_square = (root | test_bit);        
            square = 0; 
            for (j = 0; j < WIDTH; j = j + 1) 
            begin
              if (temp_square[j]) 
              begin 
                  square = square + (temp_square << j); 
              end 
            end

            if (square <= remainder) 
            begin
                root = root | test_bit; 
            end
        end
    end
endmodule

output.rtl/square_root_seq.sv:
module square_root_seq #(parameter WIDTH = 16) (
    input  wire [WIDTH-1:0] num,
    input  wire clk,
    input  wire rst,
    input  wire start,
    output reg [WIDTH/2-1:0] final_root,
    output logic done
);

reg [WIDTH-1:0] remainder;
reg [WIDTH/2-1:0] odd;
reg [WIDTH/2-1:0] square_root;
wire temp_sub;

always @(posedge clk or negedge rst) begin
    if (!rst) begin
        finish_state();
    end else {
        if (!start) begin
            finish_state();
        end else begin
            remainder = num;
            odd = 1;
            square_root = 0;
        end
    }
end

always @(posedge clk) begin
    if (done) begin
        done = 0;
        remainder = num;
        odd = 1;
        square_root = 0;
    end else begin
        if (remainder >= odd) begin
            temp_sub = 1'b1;
            remainder = remainder - odd;
            odd = odd + 2;
            square_root = square_root + 1;
        end else begin
            finish_state();
        end
    end
end

assign final_root = square_root;

endmodule

